import anthropic
import json

client = anthropic.Anthropic()

# Tool definitions for the RevOps agent
tools = [
    {
        "name": "get_crm_account",
        "description": "Fetch account details from Salesforce: company size, industry, ARR, health score, recent activity.",
        "input_schema": {
            "type": "object",
            "properties": {"account_id": {"type": "string"}},
            "required": ["account_id"],
        },
    },
    {
        "name": "get_product_usage",
        "description": "Fetch product usage metrics for an account: DAU, feature adoption, last active date, top users.",
        "input_schema": {
            "type": "object",
            "properties": {"account_id": {"type": "string"}, "days": {"type": "integer", "default": 30}},
            "required": ["account_id"],
        },
    },
    {
        "name": "research_company",
        "description": "Fetch recent news, funding rounds, job postings, and LinkedIn summary for a company.",
        "input_schema": {
            "type": "object",
            "properties": {"company_domain": {"type": "string"}},
            "required": ["company_domain"],
        },
    },
    {
        "name": "draft_outreach_email",
        "description": "Write a personalised outreach email based on account context. Returns draft only — does NOT send.",
        "input_schema": {
            "type": "object",
            "properties": {
                "to_name": {"type": "string"},
                "to_title": {"type": "string"},
                "company": {"type": "string"},
                "context": {"type": "string", "description": "Key signals to weave into the email"},
                "goal": {"type": "string", "enum": ["expansion", "renewal", "churn_save", "new_business"]},
            },
            "required": ["to_name", "to_title", "company", "context", "goal"],
        },
    },
]

def stub_tool(name: str, args: dict) -> str:
    if name == "get_crm_account":
        return json.dumps({
            "company": "Acme Corp", "arr": 48000, "health_score": 62,
            "stage": "customer", "renewal_date": "2024-11-30",
            "csm": "Jordan Lee", "last_qbr": "2024-01-15"
        })
    if name == "get_product_usage":
        return json.dumps({
            "dau_30d_avg": 12, "dau_prev_30d": 27,
            "top_features": ["reporting", "exports"],
            "last_active": "2024-07-08"
        })
    if name == "research_company":
        return json.dumps({
            "recent_news": "Acme Corp raised Series B ($22M) in June 2024",
            "job_postings": ["Head of Data Engineering", "Senior Data Analyst x3"],
            "headcount_growth": "+18% YoY"
        })
    if name == "draft_outreach_email":
        return (
            f"Subject: Quick check-in — {args['company']} + [Product]\n\n"
            f"Hi {args['to_name']},\n\n"
            f"[DRAFT based on context: {args['context'][:80]}...]\n\n"
            "Happy to jump on a 20-min call this week.\n\nBest, Jordan"
        )
    return "Unknown tool"

def run_revops_agent(account_id: str, contact: dict) -> str:
    system = (
        "You are a RevOps agent. Research the account, identify signals, and produce "
        "a personalised outreach draft. Prioritise specific, factual context over generic "
        "praise. The draft is for human review — do not send."
    )
    messages = [
        {"role": "user", "content": (
            f"Prepare a churn-save outreach for {contact['name']} ({contact['title']}) "
            f"at account {account_id}. Research the account and draft a personalised email."
        )}
    ]
    while True:
        response = client.messages.create(
            model="claude-opus-4-5", max_tokens=2048,
            system=system, tools=tools, messages=messages,
        )
        if response.stop_reason == "end_turn":
            for b in response.content:
                if b.type == "text":
                    return b.text
            return "Done"
        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            results = []
            for b in response.content:
                if b.type == "tool_use":
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": b.id,
                        "content": stub_tool(b.name, b.input),
                    })
            messages.append({"role": "user", "content": results})

result = run_revops_agent("acc_001", {"name": "Sarah Chen", "title": "VP of Data"})
print(result)
